arguments.new_str:
using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through the MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(ResearchTools.SaveNote),
    AIFunctionFactory.Create(ResearchTools.GetNotes),
};

// --- Create the agent via Microsoft Agent Framework ---
using var loggerFactory = LoggerFactory.Create(b => b
    .AddSimpleConsole(o => { o.SingleLine = true; })
    .SetMinimumLevel(LogLevel.Information));

var agent = ChatClientAgentSession.AsAIAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic:
        1. Search the web multiple times with different queries to gather information.
        2. Save important findings as notes using the SaveNote tool.
        3. After gathering enough information (at least 3 searches), retrieve
           all your notes and produce a clear, well-structured summary.
        Always cite the source URL for each finding.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools,
    loggerFactory: loggerFactory);

// --- Run the agent ---
Console.WriteLine("Research Agent Starting...");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = new AgentSession();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    options: runOptions);

Console.WriteLine("\n========== Research Summary ==========\n");
Console.WriteLine(response.Text);
Console.WriteLine("\n======================================");

// --- Tool implementations ---
public static class ResearchTools
{
    private static readonly List<(string Topic, string Content, string Source)> _notes = [];
    private static readonly HttpClient _httpClient = new();

    [Description("Search the web for information on a query. Returns search result snippets with URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🔍 Searching: {query}");

        try
        {
            // Use a web search API (DuckDuckGo instant answer as a lightweight option)
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_redirect=1";
            var json = await _httpClient.GetStringAsync(url);

            using var doc = System.Text.Json.JsonDocument.Parse(json);
            var root = doc.RootElement;
            var results = new List<string>();

            // Abstract (main answer)
            var abstractText = root.GetProperty("Abstract").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[Main] {abstractText}\nSource: {abstractUrl}");
            }

            // Related topics
            if (root.TryGetProperty("RelatedTopics", out var related))
            {
                foreach (var item in related.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) &&
                        item.TryGetProperty("FirstURL", out var itemUrl))
                    {
                        results.Add($"- {text.GetString()}\n  URL: {itemUrl.GetString()}");
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for '{query}'. Try a different query.";
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note with a topic label, content, and source URL for later summarization.")]
    public static string SaveNote(
        [Description("Short topic label for the note")] string topic,
        [Description("The content of the note")] string content,
        [Description("Source URL where the information was found")] string source)
    {
        _notes.Add((topic, content, source));
        Console.WriteLine($"  📝 Note saved: {topic}");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes to compile into a summary.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        Console.WriteLine($"  📋 Retrieving {_notes.Count} note(s)");
        var sb = new System.Text.StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (t, c, s) = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {t} ---");
            sb.AppendLine(c);
            sb.AppendLine($"Source: {s}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
}

using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
