                 {
                     if (item.TryGetProperty("Text", out var text) &&
                         item.TryGetProperty("FirstURL", out var itemUrl))
                     {
                         results.Add($"- {text.GetString()}\n  URL: {itemUrl.GetString()}");
                     }
                 }
             }

             if (results.Count == 0)
             {
                 return $"No detailed results found for '{query}'. Try a different query.";
             }

             return string.Join("\n\n", results);
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
